const rows = $("Keep Parsed Signup Rows").all();
const seen = new Set();

return rows
  .filter((item) => {
    const messageId = item.json?.message_id ?? null;
    if (!messageId || seen.has(messageId)) return false;
    seen.add(messageId);
    return Boolean(item.json?.processedStatusSql);
  })
  .map((item) => ({
    json: {
      id: item.json?.gmail_id ?? item.json?.id ?? null,
      gmail_id: item.json?.gmail_id ?? item.json?.id ?? null,
      message_id: item.json.message_id,
      processedStatusSql: item.json.processedStatusSql,
    },
  }));

const subjectNeedle = 'New membership application on ClubSpark';
const BODY_PATTERNS = [/has\s+applied\s+for/i, /has\s+renewed/i];
const sqlLiteral = (value) => {
  if (value === null || value === undefined) return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
};

return $input.all()
  .filter((item) => {
    const subject = item.json?.subject ?? '';
    const text = item.json?.normalizedText ?? item.json?.textPlain ?? item.json?.text ?? '';
    return subject.includes(subjectNeedle) || BODY_PATTERNS.some((regex) => regex.test(text));
  })
  .map((item) => {
    const json = item.json ?? {};
    return {
      json: {
        ...json,
        startStatusSql: `insert into email_status (message_id, send_date, "from", subject, status_date, status) values (${sqlLiteral(json.messageId)}, ${sqlLiteral(json.sentDate)}, ${sqlLiteral(json.fromAddress)}, ${sqlLiteral(json.subject)}, now(), 'Start processing');`,
      },
      binary: item.binary,
      pairedItem: item.pairedItem,
    };
  });

return $input.all().filter((item) => {
  const id = item.json?.id ?? null;
  return id !== null && id !== undefined && String(id).trim() !== '';
});

const required = ['signup_date', 'member', 'product'];

return $input.all().filter((item) =>
  required.every((key) => {
    const val = item.json?.[key];
    return val !== undefined && val !== null && String(val).trim() !== '';
  })
);

const decodeHtml = (value) => {
  if (!value) return '';
  return value
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&pound;/gi, '\u00A3')
    .replace(/&#163;/gi, '\u00A3')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>');
};

const htmlToText = (html) => {
  if (!html) return '';
  return decodeHtml(
    html
      .replace(/<br\s*\/?>/gi, '\n')
      .replace(/<\/p>/gi, '\n')
      .replace(/<\/div>/gi, '\n')
      .replace(/<li>/gi, '\n- ')
      .replace(/<[^>]+>/g, ' ')
      .replace(/\r/g, '')
      .replace(/[ \t]+\n/g, '\n')
      .replace(/\n{3,}/g, '\n\n')
      .trim(),
  );
};

return $input.all().map((item) => {
  const json = item.json ?? {};
  const headers = json.headers ?? json.email?.headers ?? {};
  const metadata = json.metadata ?? json.email?.metadata ?? {};
  const textHtml = json.textHtml ?? json.html ?? json.textAsHtml ?? json.bodyHtml ?? '';
  const textPlain = json.textPlain ?? json.text ?? json.bodyText ?? '';
  const normalizedText = textPlain && textPlain.trim() ? decodeHtml(textPlain) : htmlToText(textHtml);
  const fromAddress = json.fromAddress ?? json.from ?? headers['from.0'] ?? headers.from?.[0] ?? headers.from ?? json.sender ?? null;

  return {
    json: {
      ...json,
      headers,
      metadata,
      normalizedText,
      fromAddress,
      messageId: json.messageId ?? json.message_id ?? headers['message-id'] ?? headers.messageId ?? metadata['message-id'] ?? metadata.messageId ?? null,
      sentDate: json.date ?? json.sentDate ?? json.sent_date ?? headers.sent_date ?? headers.date ?? metadata.date ?? null,
      subject: json.subject ?? headers.subject ?? metadata.subject ?? null,
    },
    binary: item.binary,
    pairedItem: item.pairedItem,
  };
});

