const TRAILING_SEMICOLONS_PATTERN = /;+$/g;
const SQL_NUMBER_PATTERN = /^-?\d+(?:\.\d+)?$/;
const ACTION_PATTERN = /has\s+(?:applied\s+for|renewed)/i;

const COST_PATTERN = /(?:Total|Monthly)\s*cost\s*:\s*[\u00A3]?\s*(?<cost>\d+(?:[\.,]\d{1,2})?)/i;
const PAYER_PRODUCT_PATTERN = /^(?:Hi\s*,?\s*)?(?<payer>.*?)\s+has\s+(?:applied\s+for|renewed)\s+(?<product>.+?)\s*\.?$/i;
const MEMBER_PATTERN = /Members?\s*(?:name|names|name\(s\)|names\(s\))?\s*:\s*(?<member>.+?)(?:;|\n|$)/i;
const METHOD_PATTERN = /Payment\s*(?:method|by|type)?\s*:?\s*(?<method>.+?)(?:\n|$)/i;
const INSTALLMENT_QTY_PATTERN = /Number\s+of\s+installments\s*:\s*(?<quantity>.+?)(?:\n|$)/i;
const STATUS_PATTERNS = [
  /membership\s+is\s+"?(?<status>[^".\n]+)"?/i,
  /payment\s+will\s+appear\s+as\s+"?(?<status>[^".\n]+)"?/i,
  /payment\s+status\s+of\s+(?<status>\w+)/i,
];

const splitMembers = (value) => {
  if (!value) return [];
  return String(value)
    .split(',')
    .map((entry) => entry.replace(TRAILING_SEMICOLONS_PATTERN, '').trim())
    .filter(Boolean);
};

const sqlLiteral = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
};

const sqlNumber = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  const normalized = String(value).replace(',', '.').trim();
  return SQL_NUMBER_PATTERN.test(normalized) ? normalized : sqlLiteral(normalized);
};

const pickFirst = (text, regexes) => {
  for (const regex of regexes) {
    const match = text.match(regex);
    if (match?.groups) return match.groups;
  }
  return null;
};

const items = $input.all();
const out = [];

for (const item of items) {
  const data = item.json ?? {};
  const subject = data.subject ?? '';
  const rawText = data.normalizedText ?? data.text ?? data.textPlain ?? data.snippet ?? (data.textHtml ? htmlToText(data.textHtml) : '') ?? (data.html ? htmlToText(data.html) : '');
  const text = decodeHtml(rawText).replace(/\r/g, '');
  const flat = text.replace(/\s+/g, ' ').trim();
  const gmailId = data.id ?? data.gmail_id ?? null;

  const lines = text.split('\n').map((line) => line.trim()).filter(Boolean);
  const actionLine = lines.find((line) => ACTION_PATTERN.test(line)) ?? null;

  const payerProduct = (actionLine && actionLine.match(PAYER_PRODUCT_PATTERN)?.groups)
    ?? flat.match(/(?:Hi\s*,?\s*)?.+?\s+has\s+(?:applied\s+for|renewed)\s+.+?(?:\.|$)/i)?.[0]?.match(PAYER_PRODUCT_PATTERN)?.groups
    ?? null;

  const memberGroup = lines.map((line) => line.match(MEMBER_PATTERN)?.groups).find(Boolean)
    ?? text.match(MEMBER_PATTERN)?.groups
    ?? flat.match(MEMBER_PATTERN)?.groups
    ?? null;

  const methodGroup = lines.map((line) => line.match(METHOD_PATTERN)?.groups).find(Boolean)
    ?? text.match(METHOD_PATTERN)?.groups
    ?? flat.match(METHOD_PATTERN)?.groups
    ?? null;

  const qtyGroup = lines.map((line) => line.match(INSTALLMENT_QTY_PATTERN)?.groups).find(Boolean)
    ?? text.match(INSTALLMENT_QTY_PATTERN)?.groups
    ?? null;

  const costGroup = text.match(COST_PATTERN)?.groups ?? flat.match(COST_PATTERN)?.groups ?? null;
  const statusGroup = pickFirst(text, STATUS_PATTERNS) ?? pickFirst(flat, STATUS_PATTERNS);

  const payer = payerProduct?.payer?.trim() || data.from || data.fromAddress?.text || null;
  const product = payerProduct?.product?.trim() || null;
  const memberRaw = memberGroup?.member?.trim() || null;
  const method = methodGroup?.method?.trim() || null;
  const clubsparkStatus = statusGroup?.status?.trim() || 'Unknown';
  const quantity = qtyGroup?.quantity?.trim() || '1';
  const cost = costGroup?.cost?.replace(',', '.') || null;

  if (!cost) {
    out.push({
      json: {
        id: gmailId,
        gmail_id: gmailId,
        message_id: data.messageId ?? data.message_id ?? null,
        subject,
        parse_error: 'Neither total cost nor monthly cost could be extracted.',
        normalized_text: text,
      },
      pairedItem: item.pairedItem,
      binary: item.binary,
    });
    continue;
  }

  if (!payer || !product || !memberRaw || !method) {
    out.push({
      json: {
        id: gmailId,
        gmail_id: gmailId,
        message_id: data.messageId ?? data.message_id ?? null,
        subject,
        parse_error: 'Required membership fields were not extracted.',
        partial: { payer, product, member: memberRaw, method, clubspark_status: clubsparkStatus, cost, quantity },
        normalized_text: text,
      },
      pairedItem: item.pairedItem,
      binary: item.binary,
    });
    continue;
  }

  const members = splitMembers(memberRaw);
  if (!members.length) {
    out.push({
      json: {
        id: gmailId,
        gmail_id: gmailId,
        message_id: data.messageId ?? data.message_id ?? null,
        subject,
        parse_error: 'Member list was empty after splitting.',
        partial: { payer, product, member: memberRaw, method, clubspark_status: clubsparkStatus, cost, quantity },
        normalized_text: text,
      },
      pairedItem: item.pairedItem,
      binary: item.binary,
    });
    continue;
  }

  const signupDate = data.sentDate ?? data.send_date ?? data.date ?? new Date().toISOString();
  const type = /monthly\s*cost/i.test(text) ? 'Installments' : 'Payment';

  for (const member of members) {
    out.push({
      json: {
        id: gmailId,
        gmail_id: gmailId,
        message_id: data.messageId ?? data.message_id ?? null,
        signup_date: signupDate,
        member,
        product,
        payer,
        cost,
        quantity,
        type,
        method,
        status: 'New',
        clubspark_status: clubsparkStatus,
        batch_id: null,
        raw_member_field: memberRaw,
        subject,
        memberSignupSql: `with existing_signup as (
  select id, source
  from public.member_signups
  where lower(trim(member)) = lower(trim(${sqlLiteral(member)}))
    and lower(trim(product)) = lower(trim(${sqlLiteral(product)}))
  order by case when source = 'missing_signup_capture' then 0 else 1 end, id desc
  limit 1
), updated_backfill as (
  update public.member_signups ms
  set signup_date = ${sqlLiteral(signupDate)},
      payer = ${sqlLiteral(payer)},
      cost = ${sqlNumber(cost)},
      quantity = ${sqlNumber(quantity)},
      method = ${sqlLiteral(method)},
      status = 'New',
      clubspark_status = ${sqlLiteral(clubsparkStatus)},
      batch_id = NULL,
      source = 'email_capture'
  where ms.id in (
    select id
    from existing_signup
    where source = 'missing_signup_capture'
  )
  returning ms.id
)
insert into public.member_signups (
  signup_date,
  member,
  product,
  payer,
  cost,
  quantity,
  method,
  status,
  clubspark_status,
  batch_id,
  source
)
select
  ${sqlLiteral(signupDate)},
  ${sqlLiteral(member)},
  ${sqlLiteral(product)},
  ${sqlLiteral(payer)},
  ${sqlNumber(cost)},
  ${sqlNumber(quantity)},
  ${sqlLiteral(method)},
  'New',
  ${sqlLiteral(clubsparkStatus)},
  NULL,
  'email_capture'
where not exists (select 1 from existing_signup)
  and not exists (select 1 from updated_backfill);`,
        processedStatusSql: `update email_status set status_date = now(), status = 'Processed' where message_id = ${sqlLiteral(data.messageId ?? data.message_id ?? null)};`,
      },
      pairedItem: item.pairedItem,
      binary: item.binary,
    });
  }
}

return out;

